def token_case(s):
    exception_list = {'URL', 'ID'}
    tokens = s.split('_')
    result = ''
    for token in tokens:
        if token not in exception_list and token:  # edge case: empty string ('') is kept as is
            result += (token[0].upper() + token[1:])
        else:
            result += token
    return result.title()
